DROP DATABASE IF EXISTS ClinicaSprint1;
-- Criar banco de dados
CREATE DATABASE IF NOT EXISTS ClinicaSprint1;
USE ClinicaSprint1;

-- =========================
-- Tabela: Especialidade
-- =========================   
CREATE TABLE Especialidade (
    ID_Espec INT AUTO_INCREMENT PRIMARY KEY NOT NULL,
    Nome_Espec VARCHAR(100) NOT NULL,
    Descricao TEXT DEFAULT NULL
);

-- =========================
-- Tabela: Medico
-- =========================   
CREATE TABLE Medico (
    ID_Medico INT AUTO_INCREMENT PRIMARY KEY NOT NULL,
    Nome VARCHAR(100) NOT NULL,
    CRM VARCHAR(15) NOT NULL,
    fk_ID_Espec INT NOT NULL,
    Dt_Nasc DATE DEFAULT NULL,
    Foto MEDIUMBLOB DEFAULT NULL,
    FOREIGN KEY (fk_ID_Espec) REFERENCES Especialidade(ID_Espec)
);

-- =========================
-- Incluindo dados na tabela Especialidade
-- =========================
INSERT INTO Especialidade (Nome_Espec, Descricao) VALUES
('Dermatologista', 'Médico especialista no diagnóstico, tratamento e prevenção de doenças da pele, pelos, mucosas, cabelos e unhas.'),
('Endocrinologista', 'Médico especialista no diagnóstico, tratamento e prevenção de doenças relacionadas com os hormônios e o metabolismo. Suas atribuições envolvem cuidar desde doenças ósseas, como osteoporose, até diabetes e obesidade, passando por tumores que produzem hormônios em excesso e doenças autoimunes que afetam sua formação.'),
('Pediatra', 'Médico especializado na assistência a crianças e adolescentes, seja no aspecto preventivo ou curativo, realizando consultas de rotina e acompanhando o crescimento, medindo e pesando a criança, para comparar com exames anteriores, além de prevenir e tratar as possíveis enfermidades.');

